import React, { createContext, useContext, useState, useEffect } from 'react';
import { useSubscription } from './SubscriptionContext';
import { workoutLibrary } from '../data/workouts';

const ContentContext = createContext();

export const ContentProvider = ({ children }) => {
  const { subscription } = useSubscription();
  const userTier = subscription?.tier || 'basic';
  
  const [workouts, setWorkouts] = useState([]);
  const [filteredWorkouts, setFilteredWorkouts] = useState([]);
  const [workoutFilters, setWorkoutFilters] = useState({});
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(true);
  
  // For now, we'll use some dummy data
  useEffect(() => {
    setLoading(true);
    
    // Simulate an API call with setTimeout
    setTimeout(() => {
      // Basic workouts are available to all
      const basicWorkouts = [
        {
          id: 'ex_001',
          name: 'Seated Chair Stretch',
          duration: 10,
          level: 'Beginner',
          description: 'A gentle stretch routine you can do while seated.',
          videoUrl: '/videos/seated-chair-stretch.mp4',
          thumbnailUrl: '/images/thumbnails/seated-chair-stretch.jpg',
          tier: 'basic',
          focusArea: 'Flexibility'
        },
        {
          id: 'ex_002',
          name: 'Standing Balance Practice',
          duration: 15,
          level: 'Beginner',
          description: 'Simple exercises to improve balance and stability.',
          videoUrl: '/videos/standing-balance.mp4',
          thumbnailUrl: '/images/thumbnails/standing-balance.jpg',
          tier: 'basic',
          focusArea: 'Balance'
        }
      ];
      
      // Premium workouts are only for premium and elite tiers
      const premiumWorkouts = userTier === 'premium' || userTier === 'elite' ? [
        {
          id: 'ex_101',
          name: 'Joint-Friendly Strength Training',
          duration: 25,
          level: 'Intermediate',
          description: 'A gentle but effective strength training routine designed specifically for seniors.',
          videoUrl: '/videos/joint-friendly-strength.mp4',
          thumbnailUrl: '/images/thumbnails/joint-friendly-strength.jpg',
          tier: 'premium',
          focusArea: 'Strength'
        }
      ] : [];
      
      // Elite workouts are only for elite tier
      const eliteWorkouts = userTier === 'elite' ? [
        {
          id: 'ex_201',
          name: 'Professional Trainer Guided Session',
          duration: 35,
          level: 'Intermediate',
          description: 'A comprehensive workout session guided by a professional trainer.',
          videoUrl: '/videos/trainer-guided-session.mp4',
          thumbnailUrl: '/images/thumbnails/trainer-guided-session.jpg',
          tier: 'elite',
          focusArea: 'Full Body'
        }
      ] : [];
      
      const allWorkouts = [...basicWorkouts, ...premiumWorkouts, ...eliteWorkouts];
      setWorkouts(allWorkouts);
      setFilteredWorkouts(allWorkouts);
      setLoading(false);
    }, 1000);
  }, [userTier]);
  
  // Apply filters when they change
  useEffect(() => {
    if (!workouts.length) return;
    
    const filtered = workouts.filter(workout => {
      // Filter by duration
      if (workoutFilters.maxDuration && workout.duration > workoutFilters.maxDuration) {
        return false;
      }
      
      // Filter by level
      if (workoutFilters.level && workout.level !== workoutFilters.level) {
        return false;
      }
      
      // Filter by focus area
      if (workoutFilters.focusArea && workout.focusArea !== workoutFilters.focusArea) {
        return false;
      }
      
      return true;
    });
    
    // Apply search query
    const searchedResults = searchQuery 
      ? filtered.filter(workout => 
          workout.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
          workout.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
          (workout.focusArea && workout.focusArea.toLowerCase().includes(searchQuery.toLowerCase()))
        )
      : filtered;
    
    setFilteredWorkouts(searchedResults);
  }, [workouts, workoutFilters, searchQuery]);
  
  const updateFilters = (newFilters) => {
    setWorkoutFilters(prev => ({
      ...prev,
      ...newFilters
    }));
  };
  
  const clearFilters = () => {
    setWorkoutFilters({});
  };
  
  const value = {
    workouts: filteredWorkouts,
    allWorkouts: workouts,
    loading,
    filters: workoutFilters,
    updateFilters,
    clearFilters,
    searchQuery,
    setSearchQuery,
    userTier
  };
  
  return (
    <ContentContext.Provider value={value}>
      {children}
    </ContentContext.Provider>
  );
};

export const useContent = () => {
  const context = useContext(ContentContext);
  if (!context) {
    throw new Error('useContent must be used within a ContentProvider');
  }
  return context;
};

export default ContentContext;
